 81	const isResponse = (v: unknown): v is Response =>
 82	  typeof v === 'object' && v !== null && v instanceof Response;
 83	
 84	const reportServerError = (cause: Cause.Cause<unknown>): void => {
 85	  Bun.stderr.write(`[gycc] Effect error: ${Cause.pretty(cause)}\n`);
 86	};
 87	
 88	const throwHttpError = (error: unknown): never => {
 89	  // Tagged HTTP errors map to the matching React Router response before the raw
 90	  // `Response` passthrough.
 91	  if (RedirectError.is(error)) {
 92	    const url = typeof error.url === 'string' ? error.url : error.url.toString();
