103	  }
104	
105	  // Raw `Response` passthrough (transition + root ErrorBoundary).
106	  if (isResponse(error)) throw error;
107	
108	  reportServerError(Cause.die(error));
109	  throw new Response('Internal Server Error', { status: 500 });
110	};

