  9	/**
 10	 * In-memory `Storage` test layer (opencode keeps test layers out of the
 11	 * production module, under `test/` — per its AGENTS.md "test real impl"). This
 12	 * is the `Map`-backed fake the unit tests and the service-level round-trip
 13	 * tests provide instead of a real bucket; it lives here so `storage.server.ts`
 14	 * never ships a fake.
 15	 */
 16	
 17	export interface TestStoredObject {
 18	  readonly body: Uint8Array | string;
 19	  readonly contentType?: string;
 20	  readonly lastModified?: Date;
 21	  readonly etag?: string;
 22	}
 23	
 24	const epoch = (): Date => DateTime.toDateUtc(DateTime.makeUnsafe(0));
 25	
 26	export const layerTest = (objects: Record<string, TestStoredObject> = {}) =>
 27	  Layer.sync(Storage.Service, () => {
 28	    const entries = new Map<string, Required<TestStoredObject>>();
 29	    for (const [key, object] of Object.entries(objects)) {
 30	      entries.set(key, {
 31	        body: object.body,
 32	        contentType: object.contentType ?? 'application/json',
 33	        lastModified: object.lastModified ?? epoch(),
 34	        etag: object.etag ?? `"${key}"`,
 35	      });
 36	    }
 37	
 38	    const bytes = (body: Uint8Array | string): Uint8Array =>
 39	      typeof body === 'string' ? new TextEncoder().encode(body) : body;
 40	    const responseBody = (body: Uint8Array | string): BodyInit =>
 41	      typeof body === 'string'
 42	        ? body
 43	        : new Blob([body as Uint8Array<ArrayBuffer>]);
 44	
 45	    const get = Effect.fn('Storage.get')(function* (key: string) {
 46	      const object = entries.get(key);
 47	      if (object === undefined) return yield* new NotFound({ key });
 48	      return {
 49	        stream:
 50	          new Response(responseBody(object.body)).body ??
 51	          new ReadableStream<Uint8Array>(),
 52	        contentType: object.contentType,
 53	        size: bytes(object.body).byteLength,
 54	      };
 55	    });
 56	
 57	    const put = Effect.fn('Storage.put')(function* (
 58	      key: string,
 59	      body: Uint8Array | string,
 60	      contentType: string,
 61	    ) {
 62	      const now = yield* Clock.currentTimeMillis;
 63	      entries.set(key, {
 64	        body,
 65	        contentType,
 66	        lastModified: DateTime.toDateUtc(DateTime.makeUnsafe(now)),
 67	        etag: `"test-${now}"`,
 68	      });
 69	    });
 70	
 71	    const head = Effect.fn('Storage.head')((key: string) =>
 72	      Effect.sync(() => {
 73	        const object = entries.get(key);
 74	        if (object === undefined) return Option.none<ObjectHead>();
 75	        return Option.some<ObjectHead>({
 76	          size: bytes(object.body).byteLength,
 77	          contentType: object.contentType,
 78	          lastModified: object.lastModified,
 79	          etag: object.etag,
 80	        });
 81	      }),
 82	    );
 83	
 84	    const list = Effect.fn('Storage.list')((prefix?: string) =>
 85	      Effect.sync(() =>
 86	        [...entries.entries()]
 87	          .filter(([key]) => prefix === undefined || key.startsWith(prefix))
 88	          .map(([key, object]) => ({
 89	            key,
 90	            size: bytes(object.body).byteLength,
 91	            lastModified: object.lastModified,
 92	          })),
 93	      ),
 94	    );
 95	
 96	    const del = Effect.fn('Storage.delete')((key: string) =>
 97	      Effect.sync(() => {
 98	        entries.delete(key);
 99	      }),
100	    );
101	
102	    return Storage.Service.of({ get, put, head, list, delete: del });
103	  });

