 17	 * D4 — Railway first-party Buckets, no `@aws-sdk`). A narrow surface — `get`,
 18	 * `put`, `head`, `list`, `delete` — that the `Content`/admin layers build on
 19	 * (small-interface-deep-implementation).
 20	 *
 21	 * The module-level `layer` reads the bucket config off the `Env` service
 22	 * (opencode's strongest service convention — `export const layer` /
 23	 * `export const defaultLayer`, `packages/core/src/git.ts:347`, vs a `static`
 24	 * member). The bucket is optional everywhere (the CMS degrades to bundled
 25	 * defaults without one), so a `Storage` *instance* is only constructible when a
 26	 * bucket is configured: with `Env.bucket` absent the layer fails with
 27	 * `StorageUnconfigured`, and callers that want the degraded path (the `Content`
 28	 * service) decide not to require `Storage` rather than holding a half-built one
 29	 * (make-impossible-states-unrepresentable).
 30	 *
 31	 * The in-memory test layer lives in `storage.test-helper.ts` (opencode keeps
 32	 * test layers under `test/`, per its AGENTS.md "test real impl"), so the
 33	 * production module never ships a `Map`-backed fake.
 34	 */
 35	
 36	const StorageOp = Schema.Literals(['get', 'put', 'head', 'list', 'delete']);
 37	type StorageOp = typeof StorageOp.Type;
 38	
 39	export class StorageError extends Schema.TaggedErrorClass<StorageError>()(
 40	  'Storage.Error',
 41	  {
 42	    key: Schema.String,
 43	    op: StorageOp,
 44	    cause: Schema.optional(Schema.Defect),
 45	  },
 46	) {}
