 48	/**
 49	 * Structured not-found predicate over Bun's S3 error, mirroring opencode's
 50	 * `missing()` (`packages/opencode/src/storage/storage.ts:67-74`,
 51	 * `packages/core/src/fs-util.ts:114`) which matches on `err.code === 'ENOENT'`
 52	 * rather than substring-matching a stringified error.
 53	 *
 54	 * Bun raises a structured `S3Error` (an `Error` with `name === 'S3Error'`) for
 55	 * S3-protocol failures, carrying the upstream S3 XML `<Code>` as a `code`
 56	 * field — `'NoSuchKey'` for a missing object (confirmed against the runtime;
 57	 * `Bun.S3Error` is not an exported constructor in Bun 1.3.x, so we match the
 58	 * structured field instead of `instanceof`).
 59	 */
 60	const isNoSuchKey = (e: unknown): boolean =>
 61	  typeof e === 'object' &&
 62	  e !== null &&
 63	  'code' in e &&
 64	  (e as { readonly code?: unknown }).code === 'NoSuchKey';
 65	
 66	export class NotFound extends Schema.TaggedErrorClass<NotFound>()(
 67	  'Storage.NotFound',
 68	  { key: Schema.String },
 69	) {}
 70	
 71	export class StorageUnconfigured extends Schema.TaggedErrorClass<StorageUnconfigured>()(
 72	  'Storage.Unconfigured',
 73	  {},
 74	) {}
