189	/**
190	 * Assemble the nested override object from the editor form. Only entries whose
191	 * name is a dotted path are taken; control fields (`intent`, anything starting
192	 * with `_`) and non-string values (files) are skipped. A leaf named `chapter` /
193	 * `verse` is coerced to a number so the `BibleRef` integer fields decode.
194	 */
195	export const assembleOverrides = (
196	  entries: Iterable<readonly [string, FormDataEntryValue]>,
197	): Json => {
198	  const root: MutableJsonObject = {};
199	  for (const [name, value] of entries) {
200	    if (typeof value !== 'string') continue;
201	    if (name === 'intent' || name.startsWith('_')) continue;
202	    if (isTranslationField(name)) continue;
203	    const path = name.split('.');
204	    const leaf = path[path.length - 1];
205	    const coerced: Json =
206	      (leaf === 'chapter' || leaf === 'verse') && value.trim() !== ''
207	        ? Number(value)
208	        : value;
209	    setPath(root, path, coerced);
210	  }
211	  return root;
212	};
