214	/**
215	 * Deep-merge `overrides` onto `base`, returning a new value. Objects merge
216	 * key-by-key; arrays merge element-by-element by index (so editing
217	 * `conferences.0.themeName.en` overlays only that leaf and leaves
218	 * `conferences.0.speakers` untouched); every other value (string / number /
219	 * boolean / null) is replaced. `base` and `overrides` are never mutated.
220	 */
221	export const deepMerge = (base: Json, overrides: Json): Json => {
222	  if (isPlainObject(base) && isPlainObject(overrides)) {
223	    const result: MutableJsonObject = { ...base };
224	    for (const key of Object.keys(overrides)) {
225	      const next = overrides[key];
226	      result[key] =
227	        key in base && next !== undefined
228	          ? deepMerge(base[key] as Json, next)
229	          : (next as Json);
230	    }
231	    return result;
232	  }
233	  if (Array.isArray(base) && Array.isArray(overrides)) {
234	    const result: Json[] = [...base];
235	    for (let i = 0; i < overrides.length; i += 1) {
236	      const next = overrides[i];
237	      if (next === undefined) continue;
238	      result[i] = i < base.length ? deepMerge(base[i] as Json, next) : next;
239	    }
240	    return result;
241	  }
242	  return overrides;
243	};
