257	describe('Content cache (TTL + single-flight)', () => {
258	  /** A `Storage` whose `get` count is observable, to assert caching. */
259	  const countingStorage = (json: string) =>
260	    Layer.effect(
261	      Storage.Service,
262	      Effect.gen(function* () {
263	        const calls = yield* Ref.make(0);
264	        return Storage.Service.of({
265	          get: (key) =>
266	            key === SITE_CONTENT_KEY
267	              ? Ref.update(calls, (n) => n + 1).pipe(
268	                  Effect.as({
269	                    stream:
270	                      new Response(json).body ??
271	                      new ReadableStream<Uint8Array>(),
272	                    contentType: 'application/json',
273	                    size: json.length,
274	                  }),
275	                )
276	              : Effect.fail(new NotFound({ key })),
277	          put: (key) =>
278	            Effect.fail(
279	              new StorageError({ key, op: 'put', cause: new Error('disabled') }),
280	            ),
281	          head: () => Effect.succeed(Option.none()),
282	          list: () => Effect.succeed([]),
283	          delete: () => Effect.void,
284	        });
285	      }),
286	    );
287	
288	  /** Provide `Content` over a `countingStorage` seeded with the encoded doc. */
289	  const provideCounting = (doc: SiteContentType) =>
290	    provideContent(seededStorage(doc, countingStorage));
291	
292	  it.effect('reads once within the TTL and reloads after it expires', () =>
293	    // We can't read the private call count from outside, so assert behaviour:
294	    // two reads inside the TTL return the SAME decoded reference (the cache hit,
295	    // not a re-decode), and a read after the TTL still works (a fresh load). The
296	    // built-in `Effect.cachedInvalidateWithTTL` provides both contracts.
297	    Effect.gen(function* () {
298	      const content = yield* Content.Service;
299	      const a = yield* content.getSiteContent();
300	      const b = yield* content.getSiteContent(); // cached — same reference
301	      yield* TestClock.adjust('31 seconds'); // past the 30s TTL
302	      const c = yield* content.getSiteContent(); // reloaded
303	      expect(a === b).toBe(true);
304	      expect(c).toEqual(defaultContent);
305	    }).pipe(provideCounting(defaultContent)));
306	
307	  /**
308	   * A `Storage` whose published document can be swapped at runtime, to prove the
309	   * publish→cache-bust→read path (C5, D3): after a publish writes a new document
310	   * to the bucket, `bust()` makes the change visible on the very next read —
311	   * before the TTL elapses, with no reload otherwise.
312	   */
313	  const mutableStorage = (initial: string) =>
314	    Layer.effect(
315	      Storage.Service,
316	      Effect.gen(function* () {
317	        const body = yield* Ref.make(initial);
318	        return Storage.Service.of({
319	          get: (key) =>
320	            key === SITE_CONTENT_KEY
321	              ? Ref.get(body).pipe(
322	                  Effect.map((json) => ({
323	                    stream:
324	                      new Response(json).body ??
325	                      new ReadableStream<Uint8Array>(),
326	                    contentType: 'application/json',
327	                    size: json.length,
328	                  })),
329	                )
330	              : Effect.fail(new NotFound({ key })),
331	          // `put(SITE_CONTENT_KEY, …)` simulates a publish swapping the document.
332	          put: (key, value) =>
333	            key === SITE_CONTENT_KEY && typeof value === 'string'
334	              ? Ref.set(body, value)
335	              : Effect.fail(
336	                  new StorageError({
337	                    key,
338	                    op: 'put',
339	                    cause: new Error('unsupported'),
340	                  }),
341	                ),
342	          head: () => Effect.succeed(Option.none()),
343	          list: () => Effect.succeed([]),
344	          delete: () => Effect.void,
345	        });
346	      }),
347	    );
348	
349	  /** Provide `Content` over a `mutableStorage` seeded with the encoded doc. */
350	  const provideMutable = (doc: SiteContentType) =>
351	    provideContent(seededStorage(doc, mutableStorage));
352	
353	  const accent2026 = (content: SiteContentType): string | undefined =>
354	    content.conferences.find((c) => c.slug === '/2026')?.accentColor;
355	
356	  it.effect('bust() makes a publish visible on the next read, within the TTL (D3)', () =>
357	    Effect.gen(function* () {
358	      const editedDoc = SiteContent.make({
359	        ...defaultContent,
360	        conferences: defaultContent.conferences.map((conference) =>
361	          conference.slug === '/2026'
362	            ? { ...conference, accentColor: HexColour.make('#0a0a0a') }
363	            : conference,
364	        ),
365	      });
366	      const edited = yield* encode(editedDoc);
367	
368	      const content = yield* Content.Service;
369	      const storage = yield* Storage.Service;
370	
371	      const before = yield* content.getSiteContent(); // caches the original
372	      yield* storage.put(SITE_CONTENT_KEY, edited, 'application/json'); // publish
373	      const stale = yield* content.getSiteContent(); // still the cached original
374	      yield* content.bust(); // publish busts the cache
375	      const after = yield* content.getSiteContent(); // re-reads the bucket
376	
377	      // No TestClock advance: the publish is invisible until the bust, then live.
378	      const bundledAccent = accent2026(defaultContent);
379	      expect(accent2026(before)).toBe(bundledAccent); // bundled default
380	      expect(accent2026(stale)).toBe(bundledAccent); // cached — publish not yet seen
381	      expect(accent2026(after)).toBe('#0a0a0a'); // bust → published value
382	    }).pipe(provideMutable(defaultContent)));
383	
384	  /**
385	   * Single-flight: concurrent first-reads must not stampede the bucket. The
386	   * built-in `Effect.cachedInvalidateWithTTL` parks every reader on one
387	   * in-flight `fetchDocument` and shares its result, so the bucket is read
388	   * exactly once even when many fibers race the cold cache
389	   * (`use-the-platform`). The `Storage.get` counts its calls so we can assert
390	   * the single read directly.
391	   */
392	  it.effect('single-flights concurrent first-reads onto one bucket read', () =>
393	    Effect.gen(function* () {
394	      const content = yield* Content.Service;
395	      // Race many cold-cache reads at once; the built-in cache must collapse
396	      // them onto a single `fetchDocument`.
397	      const result = yield* Effect.all(
398	        Array.from({ length: 8 }, () => content.getSiteContent()),
399	        { concurrency: 'unbounded' },
400	      );
401	
402	      // Every racer got the bundled defaults…
403	      for (const doc of result) {
404	        expect(doc).toEqual(defaultContent);
405	      }
406	      // …and they share ONE decoded reference (proves the single in-flight load,
407	      // not eight independent decodes).
408	      expect(result.every((doc) => doc === result[0])).toBe(true);
409	    }).pipe(provideCounting(defaultContent)));
410	});
